/**
 * Shared utility helpers for @kntic/links.
 */

import { readFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import yaml from 'js-yaml';

/**
 * Default config filename.
 */
export const CONFIG_FILE = 'links.yml';

/**
 * Load and parse the links YAML config from the current directory.
 * @param {string} [dir=process.cwd()] - Directory to look in.
 * @returns {Promise<object>} Parsed config object.
 */
export async function loadConfig(dir = process.cwd()) {
  const filePath = resolve(dir, CONFIG_FILE);
  const raw = await readFile(filePath, 'utf8');
  return yaml.load(raw);
}

/**
 * Pretty-print an error and exit.
 * @param {string} message
 * @param {number} [code=1]
 */
export function fatal(message, code = 1) {
  console.error(`error: ${message}`);
  process.exit(code);
}

/**
 * Static HTML page generator for KNTIC Links.
 *
 * Produces a single, fully self-contained index.html with all CSS inlined.
 * No JavaScript in the output — works with JS disabled.
 */

import { readFileSync } from 'node:fs';
import { resolve, dirname, extname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** HTML-escape a string to prevent XSS. */
function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/** MIME type lookup for common image formats. */
function imageMime(filePath) {
  const ext = extname(filePath).toLowerCase();
  const map = {
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.avif': 'image/avif',
  };
  return map[ext] || 'application/octet-stream';
}

/**
 * Read a local image file and return a base64 data URI.
 * @param {string} filePath — path to the image (absolute or relative to configDir)
 * @param {string} configDir — directory that links.yaml lives in
 * @returns {string} data URI string
 */
export function inlineImage(filePath, configDir) {
  const abs = resolve(configDir, filePath);
  const buf = readFileSync(abs);
  const mime = imageMime(abs);
  return `data:${mime};base64,${buf.toString('base64')}`;
}

// ---------------------------------------------------------------------------
// Schedule filtering
// ---------------------------------------------------------------------------

/**
 * Filter links to only those whose schedule window includes `now`.
 * Links without scheduling fields are always included.
 */
export function filterScheduled(links, now = new Date()) {
  if (!links || !Array.isArray(links)) return [];

  return links.filter((link) => {
    if (link.scheduled_from) {
      const from = new Date(link.scheduled_from);
      if (now < from) return false;
    }
    if (link.scheduled_until) {
      const until = new Date(link.scheduled_until);
      if (now > until) return false;
    }
    return true;
  });
}

// ---------------------------------------------------------------------------
// Theme CSS loading
// ---------------------------------------------------------------------------

/**
 * Load theme CSS from the themes directory.
 * @param {string} themeName — name without .css extension
 * @returns {string} CSS content
 */
export function loadThemeCSS(themeName) {
  const themePath = resolve(__dirname, 'themes', `${themeName}.css`);
  try {
    return readFileSync(themePath, 'utf8');
  } catch {
    throw new Error(
      `Theme "${themeName}" not found at ${themePath}. ` +
      'Available themes live in src/themes/.',
    );
  }
}

// ---------------------------------------------------------------------------
// HTML generation
// ---------------------------------------------------------------------------

/**
 * Generate a complete, self-contained HTML page from a links config.
 *
 * @param {object} config — parsed links.yaml config object
 * @param {object} [options]
 * @param {string} [options.configDir=process.cwd()] — directory links.yaml lives in (for resolving relative paths)
 * @param {Date}   [options.now=new Date()]           — current time (for schedule filtering)
 * @returns {string} Complete HTML document
 */
export function generatePage(config, options = {}) {
  const configDir = options.configDir || process.cwd();
  const now = options.now || new Date();

  const name = config.name || 'My Links';
  const bio = config.bio || '';
  const theme = config.theme || 'minimal-dark';

  // Load and inline CSS
  const css = loadThemeCSS(theme);

  // Filter links by schedule
  const links = filterScheduled(config.links, now);

  // Avatar handling
  let avatarHTML = '';
  if (config.avatar && config.avatar.trim().length > 0) {
    try {
      const dataUri = inlineImage(config.avatar, configDir);
      avatarHTML = `<img class="profile__avatar" src="${dataUri}" alt="${esc(name)}" width="88" height="88">`;
    } catch {
      // Fallback: reference the file directly (it will be copied to output dir)
      avatarHTML = `<img class="profile__avatar" src="${esc(config.avatar)}" alt="${esc(name)}" width="88" height="88">`;
    }
  }

  // Build link list HTML
  const linksHTML = links.map((link) => {
    const icon = link.icon ? `<span class="links__icon">${esc(link.icon)}</span>` : '';
    const description = link.description
      ? `<span class="links__description">${esc(link.description)}</span>`
      : '';

    return `      <li class="links__item">
        <a class="links__anchor" href="${esc(link.url)}" target="_blank" rel="noopener noreferrer">
          <span class="links__label">${icon}${esc(link.label)}</span>${description}
        </a>
      </li>`;
  }).join('\n');

  // OG description falls back to bio, then a generic string
  const ogDescription = bio || `${name} — link page`;

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${esc(name)}</title>
  <meta name="description" content="${esc(ogDescription)}">
  <meta property="og:title" content="${esc(name)}">
  <meta property="og:description" content="${esc(ogDescription)}">
  <meta property="og:type" content="website">
  <style>
${css}
  </style>
</head>
<body>
  <section class="profile">
    ${avatarHTML}
    <h1 class="profile__name">${esc(name)}</h1>
${bio ? `    <p class="profile__bio">${esc(bio)}</p>\n` : ''}  </section>

  <ul class="links">
${linksHTML}
  </ul>

  <footer class="footer">
    <a class="footer__link" href="https://kntic.ai">Powered by KNTIC Links</a>
  </footer>
</body>
</html>
`;
}

/**
 * links list — List all configured links.
 *
 * Reads the nearest links.yaml and prints a formatted table of links.
 * Supports --json for machine-readable output.
 */

import chalk from 'chalk';
import { findConfig, readConfig } from '../config.js';

/**
 * Build a schedule status string for a link.
 */
function scheduleStatus(link) {
  const parts = [];
  if (link.scheduled_from) parts.push(`from ${link.scheduled_from}`);
  if (link.scheduled_until) parts.push(`until ${link.scheduled_until}`);
  if (parts.length === 0) return '';
  return `🕐 ${parts.join(' ')}`;
}

/**
 * Pad a string to a given width.
 */
function pad(str, width) {
  const len = str.length;
  return len >= width ? str : str + ' '.repeat(width - len);
}

export function registerList(program) {
  program
    .command('list')
    .description('List all links')
    .option('--json', 'Output links as a JSON array')
    .action(async (opts) => {
      // Find and read config
      let config;
      try {
        const configPath = findConfig();
        config = readConfig(configPath);
      } catch (err) {
        console.error(`Error: ${err.message}`);
        process.exitCode = 1;
        return;
      }

      const links = config.links || [];

      if (links.length === 0) {
        console.log('No links yet. Use: links add <label> <url>');
        return;
      }

      // JSON output
      if (opts.json) {
        console.log(JSON.stringify(links, null, 2));
        return;
      }

      // Calculate column widths
      const idxWidth = String(links.length).length;
      let labelWidth = 5; // minimum "LABEL"
      let urlWidth = 3;   // minimum "URL"
      let iconWidth = 0;

      const hasIcons = links.some((l) => l.icon);

      for (const link of links) {
        if (link.label.length > labelWidth) labelWidth = link.label.length;
        if (link.url.length > urlWidth) urlWidth = link.url.length;
        if (link.icon && link.icon.length > iconWidth) iconWidth = link.icon.length;
      }

      // Print header
      let header = `${pad('#', idxWidth)}  ${pad('LABEL', labelWidth)}  ${pad('URL', urlWidth)}`;
      if (hasIcons) header += `  ${pad('ICON', iconWidth)}`;
      header += '  SCHEDULE';
      console.log(chalk.bold(header));
      console.log(chalk.gray('─'.repeat(header.length)));

      // Print rows
      links.forEach((link, i) => {
        const idx = pad(String(i + 1), idxWidth);
        const label = pad(link.label, labelWidth);
        const url = pad(link.url, urlWidth);
        const icon = hasIcons ? `  ${pad(link.icon || '', iconWidth)}` : '';
        const sched = scheduleStatus(link);

        let line = `${chalk.gray(idx)}  ${chalk.cyan(label)}  ${url}${icon}`;
        if (sched) line += `  ${chalk.yellow(sched)}`;
        console.log(line);
      });
    });
}

import { readFileSync, writeFileSync, renameSync } from 'node:fs';
import { resolve, dirname, join } from 'node:path';
import yaml from 'js-yaml';

// ---------------------------------------------------------------------------
// Schema defaults
// ---------------------------------------------------------------------------

export const DEFAULT_CONFIG = {
  name: 'My Links',
  bio: '',
  avatar: '',
  theme: 'minimal-dark',
  domain: '',
  links: [],
};

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

/**
 * Validate that a URL string starts with http:// or https://.
 * @param {string} url
 * @returns {{ valid: boolean, error?: string }}
 */
export function validateUrl(url) {
  if (typeof url !== 'string' || url.length === 0) {
    return { valid: false, error: 'url must be a non-empty string' };
  }
  if (!/^https?:\/\//i.test(url)) {
    return { valid: false, error: `url must start with http:// or https:// — got "${url}"` };
  }
  return { valid: true };
}

/**
 * Validate a full config object against the links.yaml schema.
 * Collects all errors instead of failing on the first one.
 * @param {object} config
 * @returns {{ valid: boolean, errors: string[] }}
 */
export function validateConfig(config) {
  const errors = [];

  if (config === null || typeof config !== 'object' || Array.isArray(config)) {
    return { valid: false, errors: ['links.yaml: config must be a YAML mapping (object)'] };
  }

  // --- top-level required fields ---
  if (typeof config.name !== 'string' || config.name.trim().length === 0) {
    errors.push("links.yaml: missing required field 'name' (must be a non-empty string)");
  }

  // --- top-level optional string fields ---
  for (const field of ['bio', 'avatar', 'domain']) {
    if (config[field] !== undefined && config[field] !== null && typeof config[field] !== 'string') {
      errors.push(`links.yaml: field '${field}' must be a string`);
    }
  }

  // --- theme ---
  if (config.theme !== undefined && config.theme !== null) {
    if (typeof config.theme !== 'string' || config.theme.trim().length === 0) {
      errors.push("links.yaml: field 'theme' must be a non-empty string");
    }
  }

  // --- links array ---
  if (config.links !== undefined && config.links !== null) {
    if (!Array.isArray(config.links)) {
      errors.push("links.yaml: field 'links' must be an array");
    } else {
      config.links.forEach((link, i) => {
        const prefix = `links.yaml: links[${i}]`;

        if (link === null || typeof link !== 'object' || Array.isArray(link)) {
          errors.push(`${prefix} must be an object`);
          return;
        }

        // required
        if (typeof link.label !== 'string' || link.label.trim().length === 0) {
          errors.push(`${prefix}: missing required field 'label' (must be a non-empty string)`);
        }
        if (typeof link.url !== 'string' || link.url.trim().length === 0) {
          errors.push(`${prefix}: missing required field 'url' (must be a non-empty string)`);
        } else {
          const urlCheck = validateUrl(link.url);
          if (!urlCheck.valid) {
            errors.push(`${prefix}: ${urlCheck.error}`);
          }
        }

        // optional strings
        for (const field of ['icon', 'description']) {
          if (link[field] !== undefined && link[field] !== null && typeof link[field] !== 'string') {
            errors.push(`${prefix}: field '${field}' must be a string`);
          }
        }

        // optional ISO date strings
        for (const field of ['scheduled_from', 'scheduled_until']) {
          if (link[field] !== undefined && link[field] !== null) {
            if (typeof link[field] !== 'string') {
              errors.push(`${prefix}: field '${field}' must be an ISO 8601 date string`);
            } else if (Number.isNaN(Date.parse(link[field]))) {
              errors.push(`${prefix}: field '${field}' is not a valid ISO 8601 date — got "${link[field]}"`);
            }
          }
        }
      });
    }
  }

  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Config file discovery
// ---------------------------------------------------------------------------

/**
 * Walk up from `startDir` (defaults to cwd) looking for links.yaml.
 * @param {string} [startDir=process.cwd()]
 * @returns {string} Absolute path to the nearest links.yaml.
 * @throws {Error} If no links.yaml is found before reaching the filesystem root.
 */
export function findConfig(startDir = process.cwd()) {
  let dir = resolve(startDir);

  // eslint-disable-next-line no-constant-condition
  while (true) {
    const candidate = join(dir, 'links.yaml');
    try {
      readFileSync(candidate); // existence check
      return candidate;
    } catch {
      // not found — go up
    }

    const parent = dirname(dir);
    if (parent === dir) {
      throw new Error(
        'links.yaml not found. Run "links init" to create a new project.',
      );
    }
    dir = parent;
  }
}

// ---------------------------------------------------------------------------
// Read / Write
// ---------------------------------------------------------------------------

/**
 * Read, parse, and validate a links.yaml file.
 * @param {string} filePath — absolute or relative path to links.yaml
 * @returns {object} Parsed and validated config object.
 * @throws {Error} On read failure, YAML parse failure, or validation failure.
 */
export function readConfig(filePath) {
  let raw;
  try {
    raw = readFileSync(resolve(filePath), 'utf8');
  } catch (err) {
    throw new Error(`links.yaml: unable to read file "${filePath}" — ${err.message}`);
  }

  let config;
  try {
    config = yaml.load(raw);
  } catch (err) {
    throw new Error(`links.yaml: YAML parse error — ${err.message}`);
  }

  const { valid, errors } = validateConfig(config);
  if (!valid) {
    throw new Error(errors.join('\n'));
  }

  return config;
}

/**
 * Serialize a config object to YAML and write it atomically.
 * Writes to a temporary file first, then renames into place.
 * @param {string} filePath — absolute or relative path to links.yaml
 * @param {object} config — config object to persist
 */
export function writeConfig(filePath, config) {
  const dest = resolve(filePath);
  const tmp = `${dest}.tmp`;

  const content = yaml.dump(config, {
    lineWidth: 120,
    noRefs: true,
    sortKeys: false,
  });

  writeFileSync(tmp, content, 'utf8');
  renameSync(tmp, dest);
}

/**
 * links add — Add a new link entry.
 *
 * Reads the nearest links.yaml, appends a new link, and writes it back
 * atomically. Validates the URL and rejects duplicate labels.
 */

import { findConfig, readConfig, writeConfig, validateUrl } from '../config.js';

export function registerAdd(program) {
  program
    .command('add <label> <url>')
    .description('Add a new link')
    .option('--icon <emoji>', 'Icon emoji or name for the link')
    .option('--description <text>', 'Short description of the link')
    .option('--from <date>', 'Scheduled start date (ISO 8601)')
    .option('--until <date>', 'Scheduled end date (ISO 8601)')
    .option('--update', 'Replace an existing link with the same label')
    .action(async (label, url, opts) => {
      // Validate URL
      const urlCheck = validateUrl(url);
      if (!urlCheck.valid) {
        console.error(`Error: ${urlCheck.error}`);
        process.exitCode = 1;
        return;
      }

      // Find and read config
      let configPath;
      let config;
      try {
        configPath = findConfig();
        config = readConfig(configPath);
      } catch (err) {
        console.error(`Error: ${err.message}`);
        process.exitCode = 1;
        return;
      }

      // Ensure links array exists
      if (!config.links) {
        config.links = [];
      }

      // Check for duplicate label (case-insensitive)
      const existingIndex = config.links.findIndex(
        (l) => l.label.toLowerCase() === label.toLowerCase(),
      );

      if (existingIndex !== -1 && !opts.update) {
        console.error(
          `A link with label "${label}" already exists. Use --update to replace it.`,
        );
        process.exitCode = 1;
        return;
      }

      // Build link object
      const link = { label, url };
      if (opts.icon) link.icon = opts.icon;
      if (opts.description) link.description = opts.description;
      if (opts.from) link.scheduled_from = opts.from;
      if (opts.until) link.scheduled_until = opts.until;

      // Add or replace
      if (existingIndex !== -1) {
        config.links[existingIndex] = link;
      } else {
        config.links.push(link);
      }

      // Write back
      try {
        writeConfig(configPath, config);
      } catch (err) {
        console.error(`Error: could not write links.yaml — ${err.message}`);
        process.exitCode = 1;
        return;
      }

      console.log(`✓ Added: ${label} → ${url}`);
    });
}

